sql:
SELECT name
FROM batsmen
WHERE career_strike_rate = (SELECT MAX(career_strike_rate) FROM batsmen);

SELECT bowler_id, SUM(overs) AS total_overs_bowled
FROM match_details
GROUP BY bowler_id;

SELECT SUM(md.runs) AS total_runs
FROM match_details md
JOIN tournaments_matches tm ON md.match_id = tm.match_id;

external_knowledge:
- "stars of the cricket field" refers to batsmen;
- "amassed a grand total of over a thousand runs" means the total runs scored by the batsman are greater than 1000;
- "maintained a strike rate that shines brighter than the average luminosity of their peers" means the career strike rate is higher than the average career strike rate of all batsmen.

sql:
SELECT team1_score, team2_score, result
FROM match_scores
WHERE wickets_lost = 5 AND run_rate > 5.0;

external_knowledge:
- 'Shining stars' refers to the top-performing players in cricket;
- 'Lit up the field' means the players have excelled in their performances;
- 'Top 5 batsmen' refers to the batsmen with the highest total runs;
- 'Top 5 bowlers' refers to the bowlers with the highest total wickets;
- 'Extent of their brilliance' refers to the total runs scored by batsmen and the total wickets taken by bowlers.

- In cricket, a batsman's performance is often measured by the runs they score and their strike rate;
- A bowler's performance is often measured by the wickets they take and their economy rate;
- The term "shining stars" refers to the top-performing batsman and bowler pairs in each match;
- The phrase "light up each match" metaphorically describes the standout performances that stand out in the context of the match.

sql:
SELECT MAX(num_matches) AS highest_number_of_matches_played
FROM (
    SELECT team AS team_name, COUNT(*) AS num_matches
    FROM (
        SELECT team1 AS team FROM matches
        UNION ALL
        SELECT team2 AS team FROM matches
    ) AS all_teams
    GROUP BY team_name
) AS team_match_counts;

external_knowledge:
- 'Shone the brightest' refers to having a high career average;
- 'More than a dozen teams' means `total_teams > 10`;
- 'Scored at least one run' means `runs > 0`;
- 'Team A' includes batsmen who played for teams '1' or '2';
- 'Team B' includes batsmen who played for any other team.

